          <button data-admin-edit-save style="${adminBtnPrimary({ disabled: saving })}">${saving ? window.BIRTHDAY_CONFIG.strings.admin.savingBtn : window.BIRTHDAY_CONFIG.strings.admin.saveBtn}</button>
