            <h1 style="margin:0;font:400 26px/1.15 ${SERIF};color:${C.primary};white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(draft.name || (isEdit ? '…' : window.BIRTHDAY_CONFIG.strings.admin.untitledGuest))}</h1>
